n= 128
m = 128


# PUF response

def PUF(c):
    AC_f = []  # Contains PUF Boolean values
    AC = []
    for j in range(n):
        sum = 0
        for i in range(m):
            sum = sum + c[i]*TT[i][j]
        AC.append(sum)
        if sum >= 0:
            AC_f.append(1)
        else:
            AC_f.append(0)
    #print(AC)
    #print(AC_f)
    return(AC_f)

# Set up the PUF

puf_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
host = '127.0.0.1'  # Localhost
port = 12346  # Choose an open port

puf_socket.bind((host, port))
puf_socket.listen(1)
print(f"PUF is listening on {host}:{port}")

# Accept a connection
client_socket, client_address = puf_socket.accept()
print(f"Connection established with {client_address}")

# Receive the challenge c from the client
data = client_socket.recv(4096)
c = pickle.loads(data)
print(f"Received challenge: c = {c}")


# Compute PUF(c)
result = PUF(c)
puf_data = pickle.dumps(result)


print(f"PUF result: f(c) = {result}")

#Send the PUF result to the client
client_socket.sendall(puf_data)





# Close the connections
#client_socket.close()
puf_socket.close()

